import re, math
from collections import Counter
from typing import Optional, List, Tuple
import sympy as sp

# ----------------- parsing helpers -----------------

_ANS_RE = re.compile(r"<answer>\s*([-+]?\d+)\s*</answer>", re.IGNORECASE)

def _extract_answer_int(text: str) -> Optional[int]:
    if not text:
        return None
    m = _ANS_RE.search(text)
    if not m:
        return None
    try:
        return int(m.group(1))
    except Exception:
        return None

def _normalize_aime(v: Optional[int]) -> Optional[int]:
    if v is None:
        return None
    if 0 <= v <= 999:
        return v
    return None

def _majority(counter: Counter) -> Tuple[Optional[int], int, int, int]:
    if not counter:
        return None, 0, 0, 0
    (a1, c1), *rest = counter.most_common()
    c2 = rest[0][1] if rest else 0
    total = sum(counter.values())
    return a1, c1, c2, total

def _gcd_all(ints: List[int]) -> int:
    g = 0
    for x in ints:
        g = math.gcd(g, abs(int(x)))
    return g

# ----------------- prompt builders -----------------

def _base_prompt(problem_text: str) -> str:
    return (
        "Solve the following AIME problem. Show clear step-by-step reasoning, do careful arithmetic, "
        "and put the final answer as an integer in <answer>...</answer> tags.\n\n"
        f"Problem: {problem_text}\n"
    )

def _alt_prompt(problem_text: str, style: str) -> str:
    # Different “angles” help a small model escape local mistakes.
    if style == "algebra":
        extra = (
            "Prefer algebraic derivations and invariants. Keep expressions symbolic as long as possible. "
            "Only do arithmetic at the end and double-check it."
        )
    elif style == "counting":
        extra = (
            "If this is counting/probability, define the sample space carefully, use complementary counting, "
            "and sanity-check with small cases."
        )
    elif style == "geometry":
        extra = (
            "If this is geometry, introduce coordinates or vectors if helpful, track units, and verify with "
            "a quick consistency check."
        )
    else:  # "checklist"
        extra = (
            "Use a verification checklist: (1) restate variables, (2) derive key equations, (3) solve, "
            "(4) check constraints, (5) re-check arithmetic."
        )
    return (
        "Solve the following AIME problem. " + extra + "\n"
        "Put the final answer as an integer in <answer>...</answer> tags.\n\n"
        f"Problem: {problem_text}\n"
    )

def _verify_prompt(problem_text: str, candidate: int) -> str:
    return (
        "Solve the following AIME problem. A candidate final answer is given.\n"
        "Task: Verify the candidate by re-solving cleanly and checking computations. "
        "If the candidate is wrong, give the correct integer answer.\n"
        "Put ONLY the final integer in <answer>...</answer> tags.\n\n"
        f"Problem: {problem_text}\n\n"
        f"Candidate answer to verify: {candidate}\n"
    )

def _choose_prompt(problem_text: str, candidates: List[int]) -> str:
    cand_str = ", ".join(map(str, candidates))
    return (
        "Solve the following AIME problem. Several candidate answers are listed.\n"
        "Task: Determine which candidate is correct by checking each quickly (plug-in, bounds, parity, "
        "recompute key steps). If none are correct, compute the correct answer.\n"
        "Return ONLY one integer in <answer>...</answer> tags.\n\n"
        f"Problem: {problem_text}\n\n"
        f"Candidates: {cand_str}\n"
    )

# ----------------- sympy salvage (lightweight) -----------------

_INT_RE = re.compile(r"(?<![A-Za-z])[-+]?\d+(?![A-Za-z])")

def _attempt_sympy_salvage(problem_text: str, candidates: List[int]) -> Optional[int]:
    """
    Very conservative salvage: if the problem likely asks for gcd/lcm or a linear/quad numeric result,
    try to compute from integers appearing in the statement.
    This is intentionally minimal to avoid hallucinated parsing.
    """
    nums = [int(x) for x in _INT_RE.findall(problem_text)]
    if not nums:
        return None

    low = problem_text.lower()
    # gcd-type questions
    if "gcd" in low or "greatest common divisor" in low:
        g = _gcd_all(nums)
        if 0 <= g <= 999:
            return g
    # lcm-type questions (careful: can explode)
    if "lcm" in low or "least common multiple" in low:
        l = 1
        for x in nums:
            l = abs(l * x) // math.gcd(l, x) if x != 0 else l
            if l > 10**6:
                break
        if 0 <= l <= 999:
            return l

    # If candidates exist and the statement contains a modulus-like request, prefer mod reduction.
    if ("mod" in low or "remainder" in low) and candidates:
        # Often AIME asks for remainder mod something; we can't reliably parse modulus, so skip.
        return None

    return None

# ----------------- main solver -----------------

def solve(problem_text: str, call_model, call_model_n) -> int | None:
    """
    Budget-aware strategy (~<=40 total calls):
      1) 20-sample base prompt; vote.
      2) If strong majority, verify with 5 calls.
      3) If weak, do 8 calls with alternate styles; combine votes.
      4) Ask chooser among top candidates (6 calls).
      5) Final verify (3 calls).
      6) Optional conservative sympy salvage for gcd/lcm-like statements.
    """
    # ---- Batch 1: initial sampling (20) ----
    base = _base_prompt(problem_text)
    comps = call_model_n(base, n=20)
    ans = [_normalize_aime(_extract_answer_int(t)) for t in comps]
    counter = Counter(a for a in ans if a is not None)

    if not counter:
        # One extra attempt with checklist
        t = call_model(_alt_prompt(problem_text, "checklist"))
        return _normalize_aime(_extract_answer_int(t))

    top, c1, c2, total = _majority(counter)

    # Strong majority heuristic
    strong = (c1 >= 11) or (c1 >= 9 and c1 >= c2 + 5) or (c1 / max(1, total) >= 0.6)

    # ---- If strong: verify (5) ----
    if strong and top is not None:
        ver = call_model_n(_verify_prompt(problem_text, top), n=5)
        vans = [_normalize_aime(_extract_answer_int(t)) for t in ver]
        vcounter = Counter(a for a in vans if a is not None)
        if vcounter:
            vtop, vc1, vc2, vtotal = _majority(vcounter)
            # accept if verification supports it
            if vtop == top and vc1 >= 2:
                return top
            # switch if verification strongly disagrees
            if vc1 >= 3 and vtop is not None:
                return vtop
        return top

    # ---- Weak: diversify prompts (8) ----
    # These extra "angles" often fix arithmetic/approach errors in 7B.
    styles = ["algebra", "counting", "geometry", "checklist"]
    # 8 calls total: 2 per style
    alt_prompts = [_alt_prompt(problem_text, s) for s in styles for _ in range(2)]
    # call_model_n takes one prompt; so we do 4 small batches of 2 to keep within API assumptions.
    alt_answers: List[Optional[int]] = []
    for s in styles:
        alt_comps = call_model_n(_alt_prompt(problem_text, s), n=2)
        alt_answers.extend(_normalize_aime(_extract_answer_int(t)) for t in alt_comps)

    alt_counter = Counter(a for a in alt_answers if a is not None)

    # Combine: base counts + 1.5x alt counts (implemented as +2 then -0.5 not possible; use +2 and later thresholds)
    combined = Counter(counter)
    for a, k in alt_counter.items():
        combined[a] += 2 * k

    # If still too flat, prepare candidate list from combined
    final0, fc1, fc2, ftotal = _majority(combined)
    if final0 is None:
        # last resort: sympy salvage
        return _attempt_sympy_salvage(problem_text, [])

    # If combined now has a clear leader, go straight to verify
    clearer = (fc1 >= fc2 + 4) or (fc1 >= 9)
    if clearer:
        ver2 = call_model_n(_verify_prompt(problem_text, final0), n=3)
        v2 = [_normalize_aime(_extract_answer_int(t)) for t in ver2]
        v2c = Counter(a for a in v2 if a is not None)
        if v2c:
            v2top, v2c1, v2c2, _ = _majority(v2c)
            if v2top == final0 and v2c1 >= 2:
                return final0
            if v2c1 >= 2 and v2top is not None:
                return v2top
        return final0

    # ---- Chooser among top candidates (6) ----
    top_candidates = [a for a, _ in combined.most_common(6)]
    # Ensure at least 3 candidates for better discrimination
    top_candidates = [x for x in top_candidates if x is not None]
    if len(top_candidates) < 3:
        # pad from base
        for a, _ in counter.most_common(6):
            if a is not None and a not in top_candidates:
                top_candidates.append(a)
            if len(top_candidates) >= 3:
                break
    if not top_candidates:
        return _attempt_sympy_salvage(problem_text, [])

    choose_comps = call_model_n(_choose_prompt(problem_text, top_candidates[:6]), n=6)
    choose_ans = [_normalize_aime(_extract_answer_int(t)) for t in choose_comps]
    choose_counter = Counter(a for a in choose_ans if a is not None)

    # Merge chooser evidence with heavier weight
    merged = Counter(combined)
    for a, k in choose_counter.items():
        merged[a] += 3 * k

    final, mc1, mc2, mtotal = _majority(merged)
    if final is None:
        return _attempt_sympy_salvage(problem_text, top_candidates)

    # ---- Final verification (3) ----
    ver3 = call_model_n(_verify_prompt(problem_text, final), n=3)
    v3 = [_normalize_aime(_extract_answer_int(t)) for t in ver3]
    v3c = Counter(a for a in v3 if a is not None)
    if v3c:
        v3top, v3c1, v3c2, _ = _majority(v3c)
        if v3top == final and v3c1 >= 2:
            return final
        if v3c1 >= 2 and v3top is not None:
            return v3top

    # ---- Optional conservative salvage if result looks suspiciously low-support ----
    if mc1 <= 3:
        salv = _attempt_sympy_salvage(problem_text, top_candidates)
        if salv is not None:
            return salv

    return final
